// ─── Legal Document System ────────────────────────────────────────────────────
// All intercompany and employment legal documents for Wavult Group.
// Documents are generated by the system and proposed proactively when
// the system detects a legal need (new entity, new role, capital flow, etc.)

export type SigningLevel = 'L1' | 'L2' | 'L3'
export type DocStatus = 'proposed' | 'draft' | 'pending_signature' | 'signed' | 'expired' | 'rejected'
export type SignMethod = 'click' | 'email_otp' | 'bankid' | 'eid_eidas' | 'docusign'

export interface LegalDocument {
  id: string
  type: LegalDocType
  title: string
  party_a: string          // entity_id from org-graph data
  party_b: string          // entity_id from org-graph data
  signing_level: SigningLevel
  sign_method: SignMethod
  status: DocStatus
  created_at: string       // ISO date
  signed_at?: string
  expires_at?: string
  description: string
  required: boolean        // system considers this mandatory
  auto_proposed: boolean   // was this proposed by the system?
  amount?: number          // for financial agreements
  currency?: string
  royalty_rate?: number    // for IP licenses (percentage)
  notice_period_days?: number
}

export type LegalDocType =
  | 'ip_license'
  | 'management_agreement'
  | 'service_agreement'
  | 'shareholder_agreement'
  | 'intercompany_loan'
  | 'employment_contract'
  | 'nda'
  | 'data_processing_agreement'

