// ─── Jurisdiction-aware signing method resolution ─────────────────────────────

export function getSignMethodsForJurisdiction(jurisdiction: string, level: SigningLevel): SignMethod[] {
  switch (level) {
    case 'L1': return ['click']
    case 'L2':
      if (jurisdiction === 'SE') return ['bankid', 'email_otp']
      if (['EU-LT', 'EU-DE', 'EU-NL'].includes(jurisdiction)) return ['eid_eidas', 'email_otp']
      return ['email_otp'] // USA, Global, Dubai
    case 'L3':
      if (jurisdiction === 'SE') return ['bankid']
      if (jurisdiction.startsWith('EU')) return ['eid_eidas']
      return ['docusign'] // USA, Global
  }
}

