// ─── Proactive legal trigger rules ───────────────────────────────────────────
// The system checks these rules and proposes documents automatically.

export interface LegalTrigger {
  id: string
  description: string
  condition: string     // human-readable condition
  generates: LegalDocType[]
  priority: 'critical' | 'high' | 'medium'
}

